// Script Continued Below
//------------------------------------------------------------------------------------------------------------------------
// COMPANY: DISCOVER TECHNOLOGIES
// WIDGET BASE: FIELDS
//------------------------------------------------------------------------------------------------------------------------
// 2.6.0 | 2021-04-23 | mmcc | STRY0090503 Closed Incomplete is missing the color in the filter widget on the Modern 
//                                         Portal page and Chevron color is missing on the task form.
//                                         Change made in CSS only.
//
// 2.7.0 | 2021-10-25 | mmcc | STRY0108211 Stretch - Task State Chevron- Remove Tool Tips  
//                                         In HTML, for the button, removed title="State: {{data.state}}".
//                                         In CSS, make chevron non-clickable and do not change the cursor on hover.
//                                         Change made in HTML and CSS.
// 2.7.1 | 2021-12-15 | mmcc | STRY0115686 - Hide Tasker Type on trifold view
//                                         Added omit_tasker_type as bool.
//                                         Change made in HTML and Server script.
// 2.8.1 | 2023-03-20 | mmcc | STRY0136039 - State Chevron Breakpoints to prevent Wrapping Text
//                                      In HTML, added CSS selector text-nowrap to the div that shows the name;
//                                       Format whole file and made sure all closing div's were there
//                                      In Client controller, updated to use api.controller=function() with ending semi-colon
//                                      Changes made in HTML and Client controller.
//
//------------------------------------------------------------------------------------------------------------------------

(function(data) {
	var gr;

	if(input){
		data.table = input.table;
		data.sys_id = input.sys_id;
		gr = new GlideRecord(data.table);
		if(!gr.get(data.sys_id)){
			return;
		}
	} else {
		gr = $sp.getRecord();
		if (gr == null)
			return;
	}

	data.sys_id = gr.getUniqueValue();
	data.table = gr.getTableName();
	data.filter = 'sys_id='+data.sys_id;

	// 2.7.1 | 2021-12-15 | mmcc | STRY0115686 - Hide Tasker Type on trifold view
	data.omit_tasker_type = (input || {}).omit_tasker_type || (options || {}).omit_tasker_type || false;
	convertToBool(['omit_tasker_type']);

	if (data.table == "x_153465_discovert_route_task_instance") {
		data.state = gr.state.getDisplayValue().toString();
		data.tasker_type = gr.tasker_type.getDisplayValue().toString();
		data.u_wait_for_subtasks_to_finish = gr.u_wait_for_subtasks_to_finish.getDisplayValue().toString();
		data.flow = createProcessFlow(data.table, data.sys_id, data.tasker_type);
	}

	// Check the process flow
	function createProcessFlow(table, id, tasker_type) {
		//var table = gr.getTableName();
		//var id = gr.getUniqueValue();

		var gf = new GlideRecord('sys_process_flow'); //Note: GlideRecordSecure is not feasible to use on this widget that is reading values from a table enable by the process flow plugin
		gf.addActiveQuery();
		gf.addQuery('table', table);
		if (data.u_wait_for_subtasks_to_finish.toString() == "false")
			gf.addQuery('label', '!=', 'Wait for subtasks');
		gf.addQuery('description', 'CONTAINS', tasker_type);
		gf.orderBy('order');
		gf.query();

		var currentStep;
		var items = [];
		while (gf.next()) {
			var item = {};
			item.name = gf.label.toString();
			item.colour = getCurrentStep(gf.condition.toString(), table, id); //OOTB
			//item.colour = gf.label.toString();
			items.push(item);

		}	

		if (gr.getTableName() == "x_153465_discovert_route_task_instance")
			currentStep =  gr.state.getDisplayValue().toString();//*
		if (gr.getTableName() == "x_153465_discovert_war_sar_reporting")
			currentStep =  gr.status.getDisplayValue().toString();

		data.currentStep = currentStep;

		// load all colors not just the previous colors like chevron
		// items = retoActiveSuccess(items, currentStep);
		items = getAllColors(items);
		return items;
	}


	// Check the process flow query against the current job to see if the conditions match
	function getCurrentStep(step, table, id) {
		var gnr = new GlideRecord(table);
		gnr.addEncodedQuery(step);
		gnr.addQuery('sys_id', id);
		gnr.query();

		if (gnr.next()) {
			//return 'warning';
			//return gr.state.getDisplayValue().toString();//highlighted'; //*
			var currentStep;
			if (gr.getTableName() == "x_153465_discovert_route_task_instance")
				currentStep =  gr.state.getDisplayValue().toString();//*
			if (gr.getTableName() == "x_153465_discovert_war_sar_reporting")
				currentStep =  gr.status.getDisplayValue().toString();

			return currentStep;

		} else {
			//return 'primary';
			return 'default';
		}

	}

	function getAllColors(items){
		var i = 0;
		for (var key in items) {
			var value = items[key];
			if (i == items.length) {
				value.colour = 'sucess';
			} else {
				value.colour = value.name;		
			}
			i++;
		}
		return items;
	}

	// Set the previous steps in the flow to success if the current step is further down the order
	/*
	function retoActiveSuccess(items, currentStep) {
		var i = 0;
		for (var key in items) {
			var value = items[key];

			if (value.colour == currentStep) { 
			//if (value.colour == 'warning') { //OOTB
				var index = i;
				for (var j = 0; j<i; j++) {
					//items[j].colour = 'success'; //OOTB
					items[j].colour = items[j].name;
				}			
				if (index == items.length) {
					value.colour = 'sucess';
				}
				break;
			}
			i++;
		}
		return items;
	}
*/
	// 2.7.1 | 2021-12-15 | mmcc | STRY0115686 - Hide Tasker Type on trifold view
	function convertToBool(names) {
		names.forEach(function(name) {
			data[name] = data[name] == true || data[name] == 'true';
		});
	}


})(data);

//------------------------------------------------------------------------------------------------------------------------
// WIDGET BASE: FIELDS
// COMPANY: DISCOVER TECHNOLOGIES
// CUSTOMIZED BY: KARINA TORRES
//------------------------------------------------------------------------------------------------------------------------

